// Parse destination and transport mode from Korean text
const body = $input.first().json.body || $input.first().json;
const text = body.text || '';
const userLat = body.lat || 37.5665;
const userLng = body.lng || 126.9780;
const userTransportMode = body.transportMode || 'transit';

console.log('Input text:', text);

// Detect transport mode from text
let transportMode = userTransportMode;
if (/대중교통|버스|지하철|전철|기차|KTX|SRT/.test(text)) {
  transportMode = 'transit';
} else if (/자동차|차로|드라이브|운전|차량/.test(text)) {
  transportMode = 'car';
}

// Extract destination from Korean patterns
let destination = text;

// Remove common navigation phrases
const patterns = [
  /(.+?)(?:으로|로)\s*(?:가기|가는\s*길|길찾기|안내)/,
  /(.+?)(?:에|까지)\s*(?:가기|가는\s*길|길찾기|안내)/,
  /(.+?)\s*(?:가는\s*길)/,
  /(.+?)\s*(?:찾아줘|찾아주세요|알려줘|알려주세요)/,
  /(.+?)(?:으로|로|에|까지)\s*(?:대중교통|자동차|버스|지하철)/,
  /(?:대중교통으로|자동차로|버스로|지하철로)?\s*(.+?)(?:으로|로|에|까지)?\s*(?:가기|가자|갈래|가고\s*싶어)/,
  /(.+?)\s*(?:어떻게\s*가|어떻게\s*가요|가는\s*방법)/,
];

for (const pattern of patterns) {
  const match = text.match(pattern);
  if (match && match[1]) {
    destination = match[1].trim();
    // Remove leading transport mode words
    destination = destination.replace(/^(?:대중교통으로|자동차로|버스로|지하철로|도보로)\s*/, '').trim();
    break;
  }
}

// Clean up destination: remove extra whitespace
destination = destination.replace(/\s+/g, ' ').trim();

// If destination is still too long or unchanged, try to extract key noun
if (destination === text && text.length > 20) {
  // Fallback: just use the text as-is (Naver API can handle natural language)
  destination = text;
}

console.log('Extracted destination:', destination, '| Transport:', transportMode);

return [
  {
    json: {
      destination,
      transportMode,
      userLat,
      userLng,
      originalText: text,
    },
  },
];

// Format Naver Local Search API results
const data = $input.first().json;
const prevData = $('목적지 추출').first().json;

if (!data || !data.items || data.items.length === 0) {
  return [{ json: [] }];
}

/**
 * Convert Naver Local Search API coordinates to WGS84
 * Naver Local Search returns mapx/mapy as integer strings
 * where mapx = longitude * 10^7 and mapy = latitude * 10^7
 */
function convertCoords(mapx, mapy) {
  const lng = parseInt(mapx) / 10000000;
  const lat = parseInt(mapy) / 10000000;
  return { lat, lng };
}

/**
 * Strip HTML tags from Naver API response
 * (Naver wraps matched text in <b> tags)
 */
function stripHtml(str) {
  return (str || '').replace(/<[^>]*>/g, '');
}

const results = data.items.map((item, index) => {
  const { lat, lng } = convertCoords(item.mapx, item.mapy);
  return {
    index: index + 1,
    name: stripHtml(item.title),
    address: stripHtml(item.address) || stripHtml(item.roadAddress),
    roadAddress: stripHtml(item.roadAddress),
    jibunAddress: stripHtml(item.address),
    category: stripHtml(item.category),
    telephone: item.telephone || '',
    link: item.link || '',
    lat,
    lng,
  };
});

console.log('Formatted results:', JSON.stringify(results, null, 2));

return [{ json: results }];
